// Land dots as normalized centers (x,y in 0..1). Computed once at module load.
export const WORLD_DOTS: ReadonlyArray<{ x: number; y: number }> = (() => {
  const out: { x: number; y: number }[] = [];
  const { w, h, rows } = WORLD_MAP;
  for (let j = 0; j < h; j++) {
    const row = rows[j];
    for (let i = 0; i < w; i++) {
      if (row[i] === "1") out.push({ x: (i + 0.5) / w, y: (j + 0.5) / h });
    }
  }
  return out;
})();

// Project a lon/lat to the same normalized 0..1 space as the dots (clamped to the crop).
export function projectLonLat(lon: number, lat: number): { x: number; y: number } {
  const { lonMin, lonMax, latTop, latBottom } = WORLD_MAP;
  const x = (lon - lonMin) / (lonMax - lonMin);
  const y = (latTop - lat) / (latTop - latBottom);
  return { x: Math.min(1, Math.max(0, x)), y: Math.min(1, Math.max(0, y)) };
}
